.TaskerOverallStyleSheet { display: none; } /* Name of Style Sheet, do not use to style HTML */


/* Variables section start */
$min-height-standard: 55px;

/* 
Note: how the mixin math is working:
<expression> + <expression> adds the first expression's value to the second's 
Pass in a negitve value to reduce the minium standard height
*/
@mixin adjustMinHeight($heightAdjust) {
  min-height: $heightAdjust + $min-height-standard;
}

@mixin adjustTop($heightAdjust) {
  top: $heightAdjust + $min-height-standard;
}
/* Variables section end */
.dtech-item-selected-left-indicator{
  background-color:#00A4FF;
  border-radius: 0px 3px 3px 0px;
  margin-left: -10px;
  /*margin: -10px 0px -10px -10px;*/
  height:100%;
  width: 8px;
}
.dtech-item-selected-row-background{
  background: #F4F4F4;
  margin-right:-10px;
}

.dtech-table-cell-boolean-true{
  background-image: url('True16.svg');
  background-repeat: no-repeat;
  background-size: 14px 14px;
  background-position-y: 25% !important;
  padding-left: 16px;
  margin-right: 6px;
}

.dtech-table-cell-boolean-false{
  background-image: url('False16.svg');
  background-repeat: no-repeat;
  background-size: 14px 14px;
  background-position-y: 25% !important;
  padding-left: 16px;
  margin-right: 6px;
}


.modal-content {
  top: 25px;
}

.modal-header, .modal-body {
  padding: 5px 15px;
}

.dtech-modal-content-top-0 {
  top: 0;
}

.dtech-min-width-120 {
  min-width: 120px;
}

/* needed for modal to flex widgets */
.dtech-modal-relative {
  height: calc(100vh - 20vh);
  position: relative;
}

.dtech-force-column-grow {
  display: flex !important;
  flex-direction: column !important;
  flex-grow: 1 !important;
  overflow: hidden !important;
}

.dtech-bg-color-whitesmoke {
  background-color: #F5F5F5;
}

.dtech-border-top-1px-solid-light-gray {
  border-top: 1px solid #E5E5E5;
}

.dtech-border-top-2px-light {
  border-top: 2px solid #D9D9D9;
}

.dtech-container-flex-row-space-between {
  align-items: center;
  column-gap: 5px;
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
  justify-content: space-between;
}

/* 2.7.2 | 2022-01-12 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis
flexbox ellipsis start 
*/
.dtech-container-menu-row {
  align-items: center;
  column-gap: 5px;
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
}

.dtech-col-cell-flex1-middle {
  flex: 1 1 auto;
  vertical-align: middle;
}

.dtech-col-1-flex0-middle {
  flex: 0 0 auto;
  vertical-align: middle;
}

.dtech-col-2-flex-row-w40per-ellipsis {
  display: flex;
  flex-direction: row;
  width: 40%;

  .title-ellipsised {
    flex: 1 2 auto;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.dtech-col-3-flex-row-w45per-ellipsis {
  display: flex;
  flex-direction: row;
  width: 45%;

  .title-ellipsised {
    flex: 1 2 auto;
    padding: 10px 10px 10px 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.dtech-col-7-flex-row-end {
  display: flex;
  flex-direction: row;
  justify-content: flex-end;
}

.detech-col-8-flex0-middle-w30px {
  flex: 0 0 auto;
  vertical-align: middle;
  width: 30px;
}
/* flexbox ellipsis end */

/* 2.7.1 | 2021-12-15 | mmcc | DFCT0010716 - On Tabs (OU, Task) the icons did not align correctly with text at the top of the page */
.dtech-align-menu-text-icons {
  padding: 10px 0;
  vertical-align: middle;
}

/* 2.8.5 | 2023-09-07| raj  |  STRY0136615 - STRETCH-PLACEHOLDER- Header UI Control */
.dtech-menu-item-divider {
	height: 1px;
	margin: 9px 0;
	overflow: hidden;
	background-color: #e5e5e5;
}


.dtech-member-item-row {
	align-items: center;
	column-gap: 5px;
	display: flex;
	flex-direction: row;
	flex-wrap: nowrap;
}


.dtech-stack-circle-wrapper {
  position: relative;
}

.dtech-border-stack-circle-0,
.dtech-border-stack-circle-1,
.dtech-border-stack-circle-2, 
.dtech-border-stack-circle-3,
.dtech-border-stack-circle-4,
.dtech-border-stack-circle-5 {
  position: absolute;
}
.dtech-border-stack-circle-0{
  left: 10px; /*offset ten for padding*/
}
.dtech-border-stack-circle-1{
  left: 18px; /*each stacked circle moves 8 pixels*/
}
.dtech-border-stack-circle-2{
  left: 26px;
}
.dtech-border-stack-circle-3{
  left: 34px;
}
.dtech-border-stack-circle-4{
  left: 42px;
}
.dtech-border-stack-circle-5{
  left: 50px;
}


.dtech-stack-circle-0,
.dtech-stack-circle-1,
.dtech-stack-circle-2, 
.dtech-stack-circle-3,
.dtech-stack-circle-4,
.dtech-stack-circle-5 {
  position: absolute;
}

.dtech-stack-circle-0{
  left: 0px; /*offset ten for padding*/
}
.dtech-stack-circle-1{
  left: 8px;
}
.dtech-stack-circle-2{
  left: 16px;
}
.dtech-stack-circle-3{
  left: 32px;
}
.dtech-stack-circle-4{
  left: 40px;
}
.dtech-stack-circle-5{
  left: 48px;
}

div.breadcrumbs-container {
  padding-bottom: 0 !important;
  padding-top: 0 !important;
}

.dtech-tabpane-no-header-stick-posabso {
  border-radius: 0;
  border-top-width: 0;
  bottom: 5px;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  top: 15px;
}

.dtech-tabpane-with-header-stick-posabso {
  border-radius: 0;
  border-top-width: 0;
  bottom: 5px;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  /* top: 90px; */
  @include adjustTop(15px);
}

.dtech-tabpane-with-header-ribbon1-stick-top {
  /* top: 105px; */
  @include adjustTop(30px);
}

.dtech-tabpane-with-header-ribbon2-stick-top {
  /* top: 120px; */
  @include adjustTop(45px);
}

.dtech-tabpane-with-tabs-stick-posabso {
  border-radius: 0;
  border-top-width: 0;
  bottom: 5px;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  /* top: $min-height-standard */
  @include adjustTop(0px);
}

/* Use this CSS selector in uib-popover's scope var popover-class */
/* Depreciate */
.dtech-popover-container-response {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; uib-popover's HTML template will flex */
  /* padding: 30px 20px 20px 20px; use default from uib-popover */
  /* position: absolute; provided by uib-popover */
  width: 500px;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

/* Use this CSS selector in uib-popover's scope var popover-class */
.dtech-popover-container-box-shadow {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

/* 2.8.5 | 2023-09-07| raj  |  STRY0136615 - STRETCH-PLACEHOLDER- Header UI Control */
/* Use this CSS selector in the template html for the response uib-popover */
.dtech-template-response-container {
  flex-grow: 1;
  max-height: 270px;
  overflow: auto;
  padding-right: 5px;
}

/* Use this CSS selector in the popoever all larger directives to limit size to 270 and scroll (office, operaitiona) */
.dtech-template-container-270{
  flex-grow: 1;
  max-height: 270px;
  overflow: auto;
  padding-right: 5px;
}
/* Use this CSS selector in the all directives that should not be scrollable (duration, members, subtasks) */
.dtech-template-container {
  flex-grow: 1;
  overflow: auto;
  padding-right: 5px;
}

.dtech-topstick-posabso {
  border-radius: 0;
  bottom: 0;
  left: 0;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 0;
  top: 0;
}

.dtech-topstick-pos-relative {
  border-radius: 0;
  bottom: 0;
  left: 0;
  margin: 0;
  overflow: hidden;
  position: relative;
  right: 0;
  top: 0;
}

.dtech-topstick-posabso-l-r-t-10 {
  border-radius: 0;
  bottom: 0;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  top: 10px;
}

.dtech-topstick-posabso-rl-active {
  position: absolute;
  top: 0;
  bottom: 0;
/* not using these hence the -rl-active
  right: 0;
  left: 0; */
  margin: 0;
}

.dtech-panel-heading-min-height-standard {  
  /*min-height: 75px;*/
  @include adjustMinHeight(0px);
  padding: 5px 15px;
}

.dtech-tabs-min-height-standard {  
  /* min-height: 60px; */
  @include adjustMinHeight(-15px); 
}

.dtech-ul-list-type-none {
  list-style-type: none;
}

/* STRY0121805 - this setting uses flex box row with wrap and center for the header row*/
/* STRY0126833 - override left padding */
.dtech-header-row{
  display: flex;
  flex-flow: row nowrap;
  justify-content:center;
  align-items:start;
  padding: 0 0 0 0;
}
/* STRY0121805 - this setting uses flex box row with wrap and center for the counter row*/
.dtech-count-row{
  display: flex;
  flex-flow: row wrap;
  justify-content:center;
  align-items:center;
}
/* STRY0121805 - this sets the width for all of the count items */
.dtech-count-column {
  /* width: 230px; */
  padding-right: 20px;
  padding-bottom: 10px;
}

/* STRY0121805 - this sets the bottom padding menu items */
.dtech-header-column {
  padding-top: 15px;
  padding-bottom: 10px;
}
.dtech-header-column-search {
  padding: 15px 0px 10px 30px;
}
/* STRY0121339 moved into global as it is used in Tasker Header Menu Wdiget and the Tasker Home Widget */
.dtech-header-menu-tab {/*Tab Styling*/
  display: inline-block;
  /* needed height to get border outside the svg*/
  height: 42px;
  margin: 0 0 -1px;
/* NOTE: Shawn requested what is below, need to get the anchor tag to take up it's full space for this to work as the padding is pushing the anchor down without increasing the size of the row 
  padding: 15px 5px; */
  padding: 0px 15px 0px 0px;
  border-radius: 5px;
  font-weight: 400;
  text-align: center;
  color: rgba(0, 0, 0, 1);
  cursor: pointer;
}

.dtech-header-menu-tab > a {
  height: 42px;
  padding: 10px;
  border-radius: 5px;
}

.dtech-header-menu-tab > a:hover {/*Blue line on Hover*/
  background-color: rgba(217, 237, 247, 1);
}

.dtech-header-menu-tab:focus {/*Blue line on Hover*/
  outline: 2px solid rgba(20, 146, 230, 1); 
  border-radius: 5px;
}

/* User Profile show / hide */
.dtech-user-profile{
  display: none;
  position: absolute;
  z-index: 1000;
}
.dtech-user-profile-open{
  display: block;
  position: absolute;
  z-index: 1000;
}
/*
.dtech-user-profile-hide{
  display: none;
}
*/

/* GoJS popover start */
#popoverWrapper {
  display: none;
  position: absolute;
  z-index: 1000;
}

#popoverWrapperList {
  display: none;
  position: absolute;
  z-index: 1100;
}

.dtech-popover-container-avatar {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  height: 365px;
  padding: 30px 30px 30px 30px;
  position: absolute;
  width: 400px;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-popover-list-outer-container-lg {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; not needed since flex */
  display: flex;
  flex-flow: column nowrap;
  min-height: 100px;
  padding: 10px 20px;
  position: absolute;
  width: 250px; /* was 200px when font-size was 14px */
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-arrow-up:before {
  border-bottom: 10px solid $tasker-popover-arrow-color;
  border-left: 10px solid transparent;
  border-right: 10px solid transparent;
  content: '';
  height: 0;
  left: calc(100% / 2 - 10px);
  position: absolute;
  /* right: 50%; */
  top: -10px;
  width: 0;
  z-index: 2;
}

.dtech-arrow-up:after {
  border-bottom: 12px solid rgba(0, 0, 0, 0.1);
  border-left: 12px solid transparent;
  border-right: 12px solid transparent;
  content: '';
  height: 0;
  left: calc(100% /2 - 12px);
  position: absolute;
  /* right: 49%; */
  top: -12px; 
  width: 0;
  z-index: 1;
}

.dtech-popover-list-outer-container-md {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; not needed since flex */
  display: flex;
  flex-flow: column nowrap;
  min-height: 40px;
  /* min-width: 165px; */
  padding: 10px 20px;
  position: absolute;
  /* width: 200px; */
  width: max-content;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-popover-list-main-container {
  flex-flow: row nowrap;
  display: flex;
  flex: 1;
  max-height: 290px;
  overflow-y: auto;
}

.dtech-popover-list-spinner-content {
  align-self: center;
  flex: 1 1 auto;
  text-align: center;
}

.dtech-popover-list-footer-content {
  margin-left: 3.2rem; /* match width of dtech-avatar-round-* */
  margin-top: 20px; /* li has margin-bottom 10px for a total of 30px */
}

.dtech-footer-row-sticky {
  bottom: 20px;
  margin-top: 20px;
  position: absolute;
  width: calc(100% - 40px);
}

.dtech-bg-white {
  background: #FFFFFF;
}

.dtech-opacity-50 {
  opacity: 0.5;
}

.dtech-opacity-100 {
  opacity: 1.0;
}

.dtech-avatar-text-standard-14 {
  color: $tasker-text-standard-color;
  font-size: 14px;
}

.dtech-avatar-text-standard-16 {
  color: $tasker-text-standard-color;
  font-size: 16px;
}

.dtech-avatar-link {
  color: $tasker-link-color;
  font-size: 16px;
  text-decoration-line: underline;
  text-decoration-color: $tasker-link-color;
  text-decoration-style: solid;
}

/* profile photo start */
/* STRY0135276 - added a style for a 24rem pic*/
.dtech-avatar-round-16rem {
  cursor: default;
  height: 1.6rem;
  width: 1.6rem;
}

.dtech-avatar-round-24rem {
  cursor: default;
  height: 2.4rem;
  width: 2.4rem;
}

.dtech-avatar-round-32rem {
  cursor: default;
  height: 3.2rem;
  width: 3.2rem;
}

.dtech-avatar-round-64rem {
  cursor: default;
  height: 6.4rem;
  width: 6.4rem;
}

.dtech-avatar-initials-bg-color {
  background-color: #787878;
  border-radius: 50%;
  text-align: center;
  vertical-align: middle;  
  border: 2px solid #FFFFFF;
  box-shadow: 0px 2px 6px 0px rgba(0,0,0,.25);
}
.dtech-avatar-initials-bg-color:hover {
  border: 2px solid #0087D2;
  cursor: pointer !important;
}

.dtech-avatar-bg-color {
  outline: 2px solid #FFFFFF;
  background-color: $tasker-avatar-bg-color !important;
  background-repeat: no-repeat !important; 
}

.dtech-avatar-bg-color:hover {
  outline: 2px solid #0087D2;
  cursor: pointer !important;
}

.dtech-avatar-bg-color-transparent {
  background-color: transparent !important;
  box-shadow: 0px 2px 6px 0px rgba(0,0,0,.25);
}

/* profile photo end */
