/* STRY0135722 - 
   START - Updates for Data Table filters */
.dtech-table-filter-container {
  padding-left: 10px;
}

.dtech-table-filter-label {
  padding-left: 10px;
  padding-right: 2px;
  font-weight: 800;
  color: #000000;
  font-size: 14px;
}
.dtech-table-filter-count {
  padding-left: 2px;
  padding-right: 10px;
  font-weight: 400;
  color: #000000;
  font-size: 14px;
}
.dtech-table-filter-btn {
  align-items: center;
  background-color: rgba(255, 255, 255, 1);
  border-radius: 5px;
  box-shadow: 0px 1px 20px 0px rgba(0,0,0,0.15);
  padding:2px;
} 

/* sets border for disabled button*/
.dtech-table-filter-btn:disabled {
  border: 2px solid rgba(20, 146, 230, 1);
} 

/* sets the width for the filter text */
.dtech-table-filter-width-40 {
  min-width: 40px;
  padding-right: 40px;
}

