END - Updates for Count controls for Tasker Count widget and the properties page */

/* START - Updates for Count controls for Tasker Count widget and the properties page */
.dtech-filter-btn {
  align-items: center;
  height: 52px;
  background-color: rgba(255, 255, 255, 1);
  border-radius: 5px;
  box-shadow: 0px 1px 20px 0px rgba(0,0,0,0.15);
  padding:2px;
} 

/* sets border for disabled button*/
.dtech-filter-btn:disabled {
  border: 2px solid rgba(20, 146, 230, 1);
} 


.dtech-btn {
  text-align: center;
  border-radius: 5px;
  padding:10px;
}

.dtech-btn:active{
  background-color: rgba(217, 237, 247, 1);
} 

.dtech-btn:hover, .dtech-table-filter-btn:hover, .dtech-filter-btn:hover{
  background-color: rgba(217, 237, 247, 1);
  cursor: pointer;
} 

.dtech-btn-focus, .dtech-table-filter-btn-focus, .dtech-filter-btn-focus {
  outline: 2px solid #66afe9;
}

.dtech-table-cell-btn{
  padding:5px;
}

.dtech-popover-lnk {
  padding-left:2px;
  padding-right:2px;
}

.dtech-popover-btn {
  padding: 2px;
}

.dtech-popover-btn:hover, .dtech-popover-lnk:hover {
  text-decoration: underline;
  outline: 2px solid #0087D2;
  color: #0087D2;
}

.dtech-table-cell-btn:hover {
  text-decoration: underline;
}

.dtech-data-table-btn:hover{
	text-decoration:underline;
}

/* Icon Panel Updates */
.dtech-dark-btn {
  text-align: center;
  display: block;
  height:24px;
  width:24px;
  background-color: #263341;
  border-radius: 5px;
}

.dtech-dark-btn:disabled {
  background-color: rgba(38, 51, 65, 0.5);
}

.dtech-dark-btn:active{
  background-color:#394D60;
  outline: 2px solid #00A4FF;
} 

.dtech-dark-btn:hover{
  background-color:#394D60;
  outline: 2px solid #00A4FF;
  cursor: pointer;
} 

.dtech-dark-btn-focus, .dtech-popover-btn-focus {
  outline: 2px solid #0087D2;
}

/* Warning Panel */
.dtech-hover-panel{
  z-index:10000;
  position:absolute;
}

/* Icon Panel */
.dtech-icon-panel-container-box-shadow {
  background-color: #263341;
  opacity:0.5;
  border-radius: 5px;
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  
  z-index:10000;
  position:absolute;
  padding:7px;
  
  
  display: flex;
  flex-direction:row;
  flex-wrap: nowrap;
  column-gap: 10px;
  align-items:center;
/*  justify-content: space-between; */
    
}

.dtech-icon-panel-container-box-shadow:hover{
  background-color: #263341;
  opacity:1;
}

/* Order hover */
.dtech-order-circle {
  background: #757575;
  border-radius: 50%;
  width: 16px;
  height: 16px;
  display: block;
  color: white;
  text-align: center;
  vertical-align: middle;
  font-size: 13px;
  font-style:"Segoe UI";
}

.dtech-order-circle:hover {
  background: #0087D2;
}

.dtech-order-container {
  background-color: #404040;
  display: block;
}

.dtech-order-dropdown {
  background: #404040;  
  color:#9f9f9f;
  max-height: 85px;
  overflow:auto;  
}

.dtech-order-item-selected{
  background: #404040;  
  padding: 5px 0px;
  color:#9f9f9f;
  white-space: nowrap;
}

.dtech-order-item{
  background: #404040;  
  padding: 5px 0px;
  color: #FFFFFF;
  white-space: nowrap;
}

/* Action hover */
.dtech-action-dropdown {
  padding:10px;
  display: flex;
  flex-direction:row;
  flex-wrap: nowrap;
}

.dtech-action-dropdown:hover{
  background-color:#D9EDF7;
  cursor: pointer;
} 

/* the action menu needed a container to remove the margin added by the uib-popover class popover-content */
.dtech-action-menu-container {
  	margin:-9px -14px;
}

/* The action menu needed a container to remove the margin added by the uib-popover class popover-content
 so the spinner needs to have the opposite offset to be centered
 this is a copy of .dtech-popover-list-spinner-content with an margin */

.dtech-action-menu-spinner-container {
  margin: 9px 14px;
  align-self: center;
  flex: 1 1 auto;
  text-align: center;
  
}

.dtech-action-menu-item-divider {
	height: 1px;
	margin: 0 0 0 26px;
	overflow: hidden;
	background-color: #e5e5e5;
}

.dtech-user-profile-divider {
  height: 1px;
  margin: 20px -30px 20px -30px;
  overflow: hidden;
  background-color: #e5e5e5;
}

/* sets the width for the filter text */
.dtech-filter-width-200 {
  min-width: 200px;
  padding-right: 10px;
}

/* END - Updates for Count controls for Tasker Count widget and the properties page */

/* similar to Bootstrap's .flex-column.items-start */
.flexbox.items-start {
	-ms-flex-align: start;
	-webkit-box-align: start;
	-moz-align-items: flex-start;
	-webkit-align-items: flex-start;
	align-items: flex-start;
}
